using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now always sets the UTF-8 flag
        // (EFS / bit 11) and encodes entry names as UTF-8, even for non-ASCII
        // names that previously used the system code page.  Our legacy Java
        // consumer reads entry names as Shift-JIS, so we must specify the
        // encoding explicitly.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: resolving [FromKeyedServices("cache")] against
// a non-keyed registration now throws InvalidOperationException.
// Register the service as keyed to match the controller attribute.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

